def phase2_training(logger, episodes=500, seed=42, resume_from=None):
    trainer = Trainer(...)
    start_ep = 1
    if resume_from:
        ckpt_dir = Path(CHECKPOINT_DIR) / 'MAFAC' / f'ep{resume_from:05d}'
        if ckpt_dir.exists():
            for vid_file in ckpt_dir.glob('*.pt'):
                if 'trainer_state' in vid_file.name:
                    state = torch.load(vid_file)
                    trainer.episode_count = state['episode_count']
                    start_ep = state['episode_count'] + 1
    trainer.train(start_episode=start_ep)
